#!/usr/bin/env node
import { readdirSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const root = dirname(fileURLToPath(import.meta.url)) + "/..";
const folder = join(root, "html_standalones");
const out = join(root, "manifest.js");

const files = readdirSync(folder)
  .filter((f) => /\.html?$/i.test(f))
  .sort((a, b) => a.localeCompare(b, "en"));

const entries = files.map((f) => `  { filename: ${JSON.stringify(f)} }`).join(",\n");

const body = `// AUTO-GENERATED by scripts/generate-manifest.js
// Do not edit by hand — re-run \`bun run gen\` after adding files to html_standalones/.
window.DEMO_MANIFEST = [
${entries}
];
`;

writeFileSync(out, body);
console.log(`manifest.js written — ${files.length} file(s)`);
